#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=1e6+5;int f[MAXN],n;
int main(void){
	//freopen("B3636.in","r",stdin);
	//freopen("B3636.out","w",stdout);
	scanf("%d",&n);
    for(int i=2;i<=n;++i) {
        if(i&1)f[i]=f[i-1]+1;
        else f[i]=min(f[i-1]+1,f[i>>1]+1);
    }printf("%d",f[n]);
    return false;
}
